:root {
  --bg-card: #1a1f36;
  --bg-header: #2d3561;
  --bg-details: #252b4a;
  --accent: #f5a623;
  --accent-light: #ffc85c;
  --text-primary: #ffffff;
  --text-secondary: #a0a8d0;
  --text-label: #6b75a8;
  --divider: #3a4170;
  --notch: #f5f5f5;
  --barcode-bar: #a0a8d0;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.boarding-pass {
  background-color: var(--bg-card);
  border-radius: 16px;
  width: 300px;
  overflow: hidden;
}

.pass-header {
  background-color: var(--bg-header);
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 20px;
}

.airline {
  color: var(--accent);
  font-size: 14px;
  font-weight: 800;
  letter-spacing: 2px;
}

.pass-type {
  color: var(--text-secondary);
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 1.5px;
}

.route {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 20px 16px;
}

.city {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

.city--right {
  align-items: flex-end;
}

.code {
  color: var(--text-primary);
  font-size: 32px;
  font-weight: 800;
  line-height: 1;
}

.name {
  color: var(--text-secondary);
  font-size: 10px;
  font-weight: 500;
  margin-top: 4px;
}

.flight-arrow {
  display: flex;
  align-items: center;
  flex: 1;
  padding: 0 12px;
  position: relative;
}

.arrow-line {
  display: block;
  width: 100%;
  height: 1px;
  background-color: var(--divider);
}

.plane {
  color: var(--accent);
  font-size: 18px;
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  background-color: var(--bg-card);
  padding: 0 4px;
  line-height: 1;
}

.divider {
  display: flex;
  align-items: center;
  margin: 0 -1px;
}

.notch {
  width: 18px;
  height: 18px;
  background-color: var(--notch);
  border-radius: 50%;
  flex-shrink: 0;
}

.dash-line {
  flex: 1;
  border-top: 2px dashed var(--divider);
}

.details {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 14px 8px;
  padding: 16px 20px 18px;
  background-color: var(--bg-details);
}

.detail-item {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.label {
  color: var(--text-label);
  font-size: 8px;
  font-weight: 700;
  letter-spacing: 1px;
}

.value {
  color: var(--text-primary);
  font-size: 12px;
  font-weight: 600;
}

.barcode {
  display: flex;
  align-items: stretch;
  gap: 2px;
  padding: 12px 20px;
  background-color: var(--bg-details);
  height: 36px;
  border-top: 1px solid var(--divider);
}

.bar {
  background-color: var(--barcode-bar);
  width: 3px;
  flex-shrink: 0;
}

.bar--thin {
  width: 1px;
}

.bar--wide {
  width: 5px;
}
